// Fonction pour formater les prix
function formatPrix(prix) {
    return prix.toLocaleString('fr-FR', {
        style: 'currency',
        currency: 'USD',
        minimumFractionDigits: 0
    }).replace('USD', '$');
}

// Fonction pour afficher les voitures
// Fonction pour afficher les voitures
function afficherVoitures(voituresList, containerId) {
    const container = document.getElementById(containerId);
    if (!container) return;

    container.innerHTML = '';

    voituresList.forEach(voiture => {
        const voitureElement = document.createElement('div');
        voitureElement.className = 'voiture-card';

        // Gestion des prix
        let prixHTML = `<div class="prix-normal">${formatPrix(voiture.prix)}</div>`;

        // Gestion de l'image avec fallback
        const imageUrl = voiture.image || 'https://via.placeholder.com/300x200?text=Image+non+disponible';

        voitureElement.innerHTML = `
            <div class="voiture-image-container">
                <img src="${imageUrl}"
                     alt="${voiture.nom}"
                     class="voiture-image"
                     onerror="this.onerror=null; this.src='https://via.placeholder.com/300x200?text=${voiture.nom}';">
                ${!voiture.enStock ? '<div class="rupture-badge">Rupture de stock</div>' : ''}
            </div>
            <div class="voiture-details">
                <h3>${voiture.nom}</h3>
                <p class="categorie">${voiture.categorie}</p>
                <div class="prix-container">${prixHTML}</div>
            </div>
        `;

        container.appendChild(voitureElement);
    });
}


// Fonction de filtrage et tri
function filtrerEtTrierVoitures() {
    const categorie = document.getElementById('categorie').value;
    const tri = document.getElementById('tri').value;
    const containerId = 'voitures';

    let voituresFiltrees = [...voitures];

    // Filtrer par catégorie
    if (categorie !== 'all') {
        voituresFiltrees = voituresFiltrees.filter(v => v.categorie === categorie);
    }

    // Trier
    switch (tri) {
        case 'prix-asc':
            voituresFiltrees.sort((a, b) => a.prix - b.prix);
            break;
        case 'prix-desc':
            voituresFiltrees.sort((a, b) => b.prix - a.prix);
            break;
        case 'nom-asc':
            voituresFiltrees.sort((a, b) => a.nom.localeCompare(b.nom));
            break;
        case 'nom-desc':
            voituresFiltrees.sort((a, b) => b.nom.localeCompare(a.nom));
            break;
        default:
            voituresFiltrees.sort((a, b) => a.nom.localeCompare(b.nom));
    }

    afficherVoitures(voituresFiltrees, containerId);
}

// Initialisation
document.addEventListener('DOMContentLoaded', () => {
    // Chargement des pages
    if (document.getElementById('voitures')) {
        afficherVoitures(voitures, 'voitures');
        document.getElementById('categorie').addEventListener('change', filtrerEtTrierVoitures);
        document.getElementById('tri').addEventListener('change', filtrerEtTrierVoitures);
    }

    if (document.getElementById('voitures-destockage')) {
        afficherVoitures(voituresDestockage, 'voitures-destockage');
    }
});
